import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { Chart } from 'react-chartjs-2';
import 'chart.js/auto';

const Dashboard = () => {
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [data, setData] = useState({
    totalSales: 0,
    activeUsers: 0,
    inventoryStatus: 0,
  });

  useEffect(() => {
    // Simulate data fetching
    setTimeout(() => {
      setData({
        totalSales: 15000,
        activeUsers: 120,
        inventoryStatus: 80,
      });
      setLoading(false);
    }, 1000);
  }, []);

  if (loading) return <div className="text-white">Loading...</div>;
  if (error) return <div className="text-red-500">Error: {error}</div>;

  const chartData = {
    labels: ['Sales', 'Users', 'Inventory'],
    datasets: [
      {
        label: 'Metrics',
        data: [data.totalSales, data.activeUsers, data.inventoryStatus],
        backgroundColor: ['rgba(75, 192, 192, 0.2)', 'rgba(54, 162, 235, 0.2)', 'rgba(255, 206, 86, 0.2)'],
        borderColor: ['rgba(75, 192, 192, 1)', 'rgba(54, 162, 235, 1)', 'rgba(255, 206, 86, 1)'],
        borderWidth: 1,
      },
    ],
  };

  return (
    <div className="max-w-6xl mx-auto px-4 py-6">
      <h1 className="text-2xl font-bold text-white mb-4">Dashboard Overview</h1>
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        <div className="bg-gray-800 p-6 rounded-xl shadow-md">
          <h2 className="text-lg font-semibold text-white">Total Sales</h2>
          <p className="text-2xl text-indigo-400">${data.totalSales}</p>
        </div>
        <div className="bg-gray-800 p-6 rounded-xl shadow-md">
          <h2 className="text-lg font-semibold text-white">Active Users</h2>
          <p className="text-2xl text-indigo-400">{data.activeUsers}</p>
        </div>
        <div className="bg-gray-800 p-6 rounded-xl shadow-md">
          <h2 className="text-lg font-semibold text-white">Inventory Status</h2>
          <p className="text-2xl text-indigo-400">{data.inventoryStatus}%</p>
        </div>
      </div>
      <div className="mt-8">
        <Chart type="bar" data={chartData} />
      </div>
    </div>
  );
};

export default Dashboard;

