import { useState } from 'react';

interface Product {
  id: string;
  name: string;
  price: number;
  stock: number;
}

const ProductList = () => {
  const [products, setProducts] = useState<Product[]>([
    { id: '1', name: 'Product 1', price: 100, stock: 20 },
    { id: '2', name: 'Product 2', price: 150, stock: 15 },
    { id: '3', name: 'Product 3', price: 200, stock: 10 },
  ]);

  const handleDelete = (id: string) => {
    setProducts(products.filter(product => product.id !== id));
  };

  return (
    <div className="max-w-6xl mx-auto px-4 py-6">
      <h1 className="text-2xl font-bold text-white mb-4">Product Management</h1>
      <table className="min-w-full bg-gray-800 rounded-xl">
        <thead>
          <tr>
            <th className="text-left p-4 text-white">Name</th>
            <th className="text-left p-4 text-white">Price</th>
            <th className="text-left p-4 text-white">Stock</th>
            <th className="text-left p-4 text-white">Actions</th>
          </tr>
        </thead>
        <tbody>
          {products.map(product => (
            <tr key={product.id} className="border-b border-gray-700">
              <td className="p-4 text-gray-300">{product.name}</td>
              <td className="p-4 text-gray-300">${product.price}</td>
              <td className="p-4 text-gray-300">{product.stock}</td>
              <td className="p-4">
                <button
                  onClick={() => handleDelete(product.id)}
                  className="px-4 py-2 rounded-lg bg-red-600 text-white hover:bg-red-500 transition"
                >
                  Delete
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default ProductList;
